 Begin SlaMap 	# Conversion between sky coordinate systems
    Nin = 2 	# Number of input coordinates
 IsA Mapping 	# Mapping between coordinate systems
    Nsla = 2 	# Number of conversion steps
    Sla1 = "EQECL" 	# Equatorial J2000.0 (FK5) to ecliptic (IAU 1980)
    Sla1a = 2000 	# TDB of mean ecliptic (as MJD)
    Sla2 = "ECLEQ" 	# Ecliptic (IAU 1980) to J2000.0 equatorial (FK5)
    Sla2a = 2000 	# TDB of mean ecliptic (as MJD)
 End SlaMap
